using System;`nusing GestaoManutencao.Core.Domain;`nusing GestaoManutencao.Core.Interfaces;`nusing GestaoManutencao.Core.Exceptions;`n`nnamespace GestaoManutencao.Core.States`n{`n    public class EstadoEmAndamento : ISolicitacaoState`n    {`n        public string Nome => "Em Andamento";`n`n        public void AtribuirTecnico(SolicitacaoManutencao solicitacao, Tecnico tecnico)`n        {`n            if (!tecnico.PossuiEspecialidade(solicitacao.Equipamento.EspecialidadeRequerida))`n                throw new TecnicoIncompativelException($"O tecnico {tecnico.Nome} nao possui a especialidade {solicitacao.Equipamento.EspecialidadeRequerida} exigida pelo equipamento.");`n`n            solicitacao.ForcarAtribuicaoTecnico(tecnico);`n        }`n`n        public void AdicionarServico(SolicitacaoManutencao solicitacao, ServicoRealizado servico)`n        {`n            solicitacao.ForcarAdicaoServico(servico);`n        }`n`n        public void Avancar(SolicitacaoManutencao solicitacao)`n        {`n            solicitacao.DefinirEstado(new EstadoFinalizada());`n        }`n`n        public void Cancelar(SolicitacaoManutencao solicitacao, string justificativa)`n        {`n            if (string.IsNullOrWhiteSpace(justificativa))`n                throw new ArgumentException("Justificativa eh obrigatoria para cancelamento.");`n`n            solicitacao.DefinirEstado(new EstadoCancelada(justificativa));`n        }`n    }`n}
